mapper.select:
select wi.*
from wf_instance wi
left join wf_biz_ref wr on wr.instance_id = wi.id and  wr.ref_type = 'PRIMARY'


       and wr.biz_type = #{bo.bizType}



        and wr.biz_no LIKE CONCAT('%', #{bo.bizNo}, '%')



        and wi.status = #{bo.instanceStatus}



        and wi.start_time = #{bo.instanceStartTime}


        and wi.end_time = #{bo.instanceEndTime}


        and wi.end_reason = #{bo.endReason}


        AND wi.starter_id = #{userId}
